SELECT COUNT(*) AS total_commands
FROM device_controls
WHERE device_id = 0;

SELECT AVG(battery_level) AS average_battery_level
FROM sensor_data
WHERE time >= (strftime('%s', 'now') - 86400);

SELECT sensor_name
FROM sensors
ORDER BY sensor_name;

SELECT AVG(accuracy) AS average_accuracy
FROM predictive_models
WHERE last_trained >= DATE('now', '-6 months');
